import logging, random, string, json, os, base64, io, asyncio
from datetime import datetime, timedelta
from telegram import Update, ReplyKeyboardMarkup, InlineKeyboardMarkup, InlineKeyboardButton
from telegram.ext import (
    Application, CommandHandler, MessageHandler,
    CallbackQueryHandler, ContextTypes, ConversationHandler, filters
)

logging.basicConfig(level=logging.INFO)

# ─────────────────────────────────────────────
# ⚙️  KONFIGURASI — WAJIB DIISI
# ─────────────────────────────────────────────
BOT_TOKEN  = os.getenv("NS_STORE_BOT_TOKEN") or os.getenv("BOT_TOKEN", "")
ADMIN_ID   = int(os.getenv("ADMIN_ID", "1038443084"))
HISTORY_CHANNEL_ID = os.getenv("NS_STORE_HISTORY_CHANNEL_ID") or os.getenv("HISTORY_CHANNEL_ID")
KONTAK     = "@ItsMeNovs"

# ─────────────────────────────────────────────
# 📷 QRIS IMAGE — Base64 encoded
#
# CARA GANTI QRIS:
#   1. Buka terminal / Termux
#   2. Jalankan perintah:
#        python3 -c "import base64; print(base64.b64encode(open('qris.jpg','rb').read()).decode())"
#   3. Copy hasilnya (string panjang)
#   4. Paste di bawah menggantikan tulisan: PASTE_BASE64_QRIS_DISINI
#
# Setelah di-paste, bot tidak butuh file qris.jpg sama sekali.
# ─────────────────────────────────────────────
QRIS_BASE64 = ""

def get_qris_bytes():
    """Decode base64 QRIS menjadi bytes. Return None jika belum diset."""
    if not QRIS_BASE64.strip():
        return None
    try:
        return base64.b64decode(QRIS_BASE64)
    except Exception:
        return None

# ─────────────────────────────────────────────
# 💰 PAKET PLAN
# ─────────────────────────────────────────────
PLANS = {
    "1": {"nama": "1 Hari",  "durasi": 1, "harga": 10_000, "motion_plan": "1day"},
    "2": {"nama": "3 Hari",  "durasi": 3, "harga": 20_000, "motion_plan": "3day"},
    "3": {"nama": "7 Hari",  "durasi": 7, "harga": 50_000, "motion_plan": "7day"},
}

# ─────────────────────────────────────────────
# 💾 DATABASE JSON
# ─────────────────────────────────────────────
DB_FILE   = "ns_store_db.json"
KEYS_FILE = "activation_keys.json"   # ← file yang dibaca Motion Bot

def load_db():
    if not os.path.exists(DB_FILE):
        return {"orders": {}, "aktivasi": {}}
    with open(DB_FILE, "r") as f:
        return json.load(f)

def save_db(db):
    with open(DB_FILE, "w") as f:
        json.dump(db, f, indent=2, ensure_ascii=False)

def load_keys():
    if not os.path.exists(KEYS_FILE):
        return {}
    with open(KEYS_FILE, "r") as f:
        return json.load(f)

def save_keys(keys):
    with open(KEYS_FILE, "w") as f:
        json.dump(keys, f, indent=2, ensure_ascii=False)

# ─────────────────────────────────────────────
# 🔧 HELPER
# ─────────────────────────────────────────────
def buat_kode_unik():
    db = load_db()
    used = {o["kode_unik"] for o in db["orders"].values() if o["status"] in ["pending", "menunggu_verifikasi"]}
    while True:
        kode = str(random.randint(100, 999))
        if kode not in used:
            return kode

def buat_kode_aktivasi():
    keys = load_keys()
    while True:
        parts = [''.join(random.choices(string.ascii_uppercase + string.digits, k=5)) for _ in range(5)]
        kode = "-".join(parts)
        if kode not in keys:
            return kode

def simpan_kode_ke_motion(kode, plan, expire_ts):
    keys = load_keys()
    keys[kode] = {
        "plan":      plan,
        "used":      False,
        "created":   datetime.now().isoformat(),
        "expire_ts": expire_ts,
    }
    save_keys(keys)

def format_rupiah(n):
    return f"Rp {n:,.0f}".replace(",", ".")

def main_keyboard():
    return ReplyKeyboardMarkup([
        ["📦 Pilih Plan", "❓ Cara Order"],
        ["📊 Status Akses", "📞 Kontak Admin"],
        ["ℹ️ Pusat Informasi"],
    ], resize_keyboard=True)

def admin_keyboard(order_id):
    return InlineKeyboardMarkup([
        [InlineKeyboardButton("✅ Konfirmasi & Kirim Kode Aktivasi", callback_data=f"ok_{order_id}")],
        [InlineKeyboardButton("❌ Tolak & Beritahu User",            callback_data=f"tolak_{order_id}")],
    ])

def user_label(user):
    if not user:
        return "-"
    username = f"@{user.username}" if user.username else "-"
    return f"{user.first_name or '-'} ({username}) | ID: {user.id}"

async def audit_event(ctx: ContextTypes.DEFAULT_TYPE, title: str, lines=None, update: Update = None):
    if not HISTORY_CHANNEL_ID:
        return
    try:
        payload = [f"🧾 NS Store Bot — {title}", f"⏰ {datetime.now().strftime('%d/%m/%Y %H:%M:%S')}"]
        if update and update.effective_user:
            payload.append(f"👤 {user_label(update.effective_user)}")
        if lines:
            payload.extend(str(line) for line in lines if line is not None)
        await ctx.bot.send_message(chat_id=HISTORY_CHANNEL_ID, text="\n".join(payload))
    except Exception as e:
        logging.warning("Gagal kirim history NS Store: %s", e)

# ─────────────────────────────────────────────
# STATE
# ─────────────────────────────────────────────
PILIH_PLAN, TUNGGU_BUKTI = range(2)

# ─────────────────────────────────────────────
# /start
# ─────────────────────────────────────────────
async def start(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    user = update.effective_user
    nama = user.first_name
    # Cek user baru (belum pernah ada di DB orders maupun aktivasi)
    db_check = load_db()
    user_pernah_order = any(
        str(o.get("user_id")) == str(user.id) for o in db_check["orders"].values()
    )
    if not user_pernah_order:
        await audit_event(ctx, "👤 User Baru", [
            f"Bergabung pertama kali ke NS Store Bot."
        ], update=update)
    await update.message.reply_text(
        f"👋 Halo, *{nama}*!\n\n"
        f"Selamat datang di *NS STORE BOT ORDER* 🤖\n"
        f"⚙️ _Platform Akses Motion Control Tools_\n\n"
        f"🛒 Beli paket akses di sini, lalu masukkan kode aktivasi\n"
        f"ke *Bot Motion Control* untuk mulai generate video AI! 🎬\n\n"
        f"Pilih menu di bawah untuk mulai:",
        parse_mode="Markdown",
        reply_markup=main_keyboard()
    )

# ─────────────────────────────────────────────
# PILIH PLAN
# ─────────────────────────────────────────────
async def pilih_plan(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    markup = ReplyKeyboardMarkup(
        [["1", "2", "3"], ["❌ Batal"]],
        resize_keyboard=True, one_time_keyboard=True
    )
    await update.message.reply_text(
        "📦 *PILIH PAKET AKSES*\n"
        "─────────────────────\n"
        "1️⃣  *1 Hari*  — Rp 10.000\n"
        "2️⃣  *3 Hari*  — Rp 20.000\n"
        "3️⃣  *7 Hari*  — Rp 50.000\n"
        "─────────────────────\n"
        "💡 Banyaknya video yang bisa dibuat tergantung\n"
        "kredit API Key kamu & durasi tiap video.\n\n"
        "Ketik *1*, *2*, atau *3*:",
        parse_mode="Markdown",
        reply_markup=markup
    )
    return PILIH_PLAN

async def proses_plan(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    pilihan = update.message.text.strip()

    if pilihan == "❌ Batal":
        await update.message.reply_text("❌ Dibatalkan.", reply_markup=main_keyboard())
        return ConversationHandler.END

    if pilihan not in PLANS:
        await update.message.reply_text("❌ Ketik 1, 2, atau 3.")
        return PILIH_PLAN

    plan        = PLANS[pilihan]
    user        = update.effective_user
    kode_unik   = buat_kode_unik()
    total_bayar = plan["harga"] + int(kode_unik)
    order_id    = f"{user.id}_{int(datetime.now().timestamp())}"
    waktu       = datetime.now().strftime("%d/%m/%Y %H:%M:%S")

    expire_order = datetime.now().timestamp() + (3 * 60)  # 3 menit
    db = load_db()
    db["orders"][order_id] = {
        "user_id"     : user.id,
        "username"    : user.username or "-",
        "nama"        : user.first_name,
        "plan"        : plan["nama"],
        "motion_plan" : plan["motion_plan"],
        "durasi"      : plan["durasi"],
        "harga"       : plan["harga"],
        "kode_unik"   : kode_unik,
        "total_bayar" : total_bayar,
        "status"      : "pending",
        "waktu"       : waktu,
        "expire_order": expire_order,
    }
    save_db(db)
    ctx.user_data["order_id"] = order_id

    await audit_event(ctx, "🛒 Order Dibuat", [
        f"📦 Paket    : {plan['nama']}",
        f"💵 Total    : {format_rupiah(total_bayar)}",
        f"🔢 Kode Unik: {kode_unik}",
        f"🆔 Order ID : {order_id}",
    ], update=update)

    await update.message.reply_text(
        f"🛒 *ORDER DIBUAT!*\n"
        f"─────────────────────\n"
        f"📦 Paket     : *{plan['nama']}*\n"
        f"💰 Harga     : {format_rupiah(plan['harga'])}\n"
        f"🔢 Kode Unik : `{kode_unik}`\n"
        f"💵 *Total Bayar: {format_rupiah(total_bayar)}*\n"
        f"─────────────────────\n"
        f"📲 *Cara Bayar:*\n"
        f"1️⃣ Scan QRIS di bawah\n"
        f"2️⃣ Masukkan nominal *{format_rupiah(total_bayar)}* persis\n"
        f"3️⃣ Bayar & screenshot bukti\n"
        f"4️⃣ Kirim foto bukti ke sini\n\n"
        f"⏳ *Batas waktu bayar: 3 menit*\n"
        f"⚠️ Lewat dari itu order otomatis dibatalkan!",
        parse_mode="Markdown",
        reply_markup=ReplyKeyboardMarkup([["❌ Batal"]], resize_keyboard=True)
    )

    # ── Kirim QRIS dari base64 (tidak butuh file di disk) ──
    qris_bytes = get_qris_bytes()
    if qris_bytes:
        await update.message.reply_photo(
            photo=io.BytesIO(qris_bytes),
            caption=(
                f"📲 Scan QRIS & bayar *{format_rupiah(total_bayar)}*\n"
                f"🔢 Kode unik: `{kode_unik}`\n\n"
                f"Setelah bayar, *kirim foto bukti transfer* ke sini 👆"
            ),
            parse_mode="Markdown"
        )
    else:
        await update.message.reply_text(
            f"⚠️ QRIS belum dikonfigurasi admin.\n"
            f"Hubungi {KONTAK} untuk info pembayaran manual.",
            parse_mode="Markdown"
        )

    return TUNGGU_BUKTI

# ─────────────────────────────────────────────
# TERIMA BUKTI TRANSFER
# ─────────────────────────────────────────────
async def terima_bukti(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    user     = update.effective_user
    order_id = ctx.user_data.get("order_id")

    if not order_id:
        await update.message.reply_text("❌ Sesi habis. Mulai ulang dengan /start.", reply_markup=main_keyboard())
        return ConversationHandler.END

    db = load_db()
    if order_id not in db["orders"]:
        await update.message.reply_text("❌ Order tidak ditemukan.", reply_markup=main_keyboard())
        return ConversationHandler.END

    order = db["orders"][order_id]

    # Cek batas waktu 3 menit
    expire_order = order.get("expire_order", 0)
    if datetime.now().timestamp() > expire_order:
        db["orders"][order_id]["status"] = "expired"
        save_db(db)
        await audit_event(ctx, "⏰ Order Expired", [
            f"📦 Paket   : {order['plan']}",
            f"💵 Total   : {format_rupiah(order['total_bayar'])}",
            f"🆔 Order ID: {order_id}",
        ], update=update)
        await update.message.reply_text(
            "⏰ *Waktu pembayaran habis!*\n\n"
            "Order otomatis dibatalkan karena melebihi batas 3 menit.\n"
            "Silakan order ulang dengan /start.",
            parse_mode="Markdown",
            reply_markup=main_keyboard()
        )
        return ConversationHandler.END
    db["orders"][order_id]["status"] = "menunggu_verifikasi"
    save_db(db)

    await audit_event(ctx, "📸 Bukti Transfer Masuk", [
        f"📦 Paket   : {order['plan']}",
        f"💵 Total   : {format_rupiah(order['total_bayar'])}",
        f"🔢 Kode Unik: {order['kode_unik']}",
        f"🆔 Order ID: {order_id}",
    ], update=update)

    await update.message.reply_text(
        f"✅ *Bukti diterima!*\n\n"
        f"📦 Paket  : {order['plan']}\n"
        f"💵 Total  : {format_rupiah(order['total_bayar'])}\n\n"
        f"⏳ Menunggu verifikasi admin...\n"
        f"Kode aktivasi akan dikirim ke sini setelah diverifikasi.\n\n"
        f"📞 Hubungi {KONTAK} jika butuh bantuan.",
        parse_mode="Markdown",
        reply_markup=main_keyboard()
    )

    caption_admin = (
        f"📸 *BUKTI TRANSFER MASUK*\n"
        f"─────────────────────\n"
        f"👤 User    : {user.first_name} (@{user.username or '-'})\n"
        f"🆔 User ID : `{user.id}`\n"
        f"📦 Paket   : {order['plan']}\n"
        f"🔢 Kode Unik: `{order['kode_unik']}`\n"
        f"💵 Total   : *{format_rupiah(order['total_bayar'])}*\n"
        f"⏰ Waktu   : {order['waktu']}\n"
        f"─────────────────────\n"
        f"Verifikasi pembayaran lalu tekan tombol:"
    )

    if update.message.photo:
        await ctx.bot.send_photo(
            chat_id=ADMIN_ID,
            photo=update.message.photo[-1].file_id,
            caption=caption_admin,
            parse_mode="Markdown",
            reply_markup=admin_keyboard(order_id)
        )
    elif update.message.document:
        await ctx.bot.send_document(
            chat_id=ADMIN_ID,
            document=update.message.document.file_id,
            caption=caption_admin,
            parse_mode="Markdown",
            reply_markup=admin_keyboard(order_id)
        )
    else:
        await ctx.bot.send_message(
            chat_id=ADMIN_ID,
            text=caption_admin + f"\n\n📝 Pesan user: {update.message.text or '-'}",
            parse_mode="Markdown",
            reply_markup=admin_keyboard(order_id)
        )

    # Forward bukti ke history channel
    if HISTORY_CHANNEL_ID:
        try:
            caption_hist = (
                f"📸 Bukti Transfer\n"
                f"👤 {user.first_name} (@{user.username or '-'})\n"
                f"📦 {order['plan']}\n"
                f"💵 {format_rupiah(order['total_bayar'])}"
            )
            if update.message.photo:
                await ctx.bot.send_photo(
                    chat_id=HISTORY_CHANNEL_ID,
                    photo=update.message.photo[-1].file_id,
                    caption=caption_hist
                )
            elif update.message.document:
                await ctx.bot.send_document(
                    chat_id=HISTORY_CHANNEL_ID,
                    document=update.message.document.file_id,
                    caption=caption_hist
                )
        except Exception:
            pass

    ctx.user_data.clear()
    return ConversationHandler.END

async def bukti_bukan_foto(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    await update.message.reply_text(
        "📸 Tolong kirim *foto* bukti transfer ya, bukan teks.\n"
        "Screenshot dari aplikasi bank/e-wallet kamu.",
        parse_mode="Markdown"
    )
    return TUNGGU_BUKTI

# ─────────────────────────────────────────────
# ADMIN: KONFIRMASI / TOLAK
# ─────────────────────────────────────────────
async def admin_callback(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    query = update.callback_query
    await query.answer()

    if query.from_user.id != ADMIN_ID:
        await query.answer("❌ Akses ditolak!", show_alert=True)
        return

    aksi, order_id = query.data.split("_", 1)
    db = load_db()

    if order_id not in db["orders"]:
        await query.edit_message_caption("❌ Order tidak ditemukan.")
        return

    order = db["orders"][order_id]

    if order["status"] not in ["pending", "menunggu_verifikasi"]:
        await query.edit_message_caption(
            f"⚠️ Order sudah diproses. Status: {order['status']}"
        )
        return

    if aksi == "tolak":
        db["orders"][order_id]["status"] = "ditolak"
        save_db(db)

        try:
            await query.edit_message_caption(
                f"❌ *Order Ditolak*\n\n"
                f"👤 {order['nama']} (@{order['username']})\n"
                f"📦 {order['plan']} — {format_rupiah(order['total_bayar'])}",
                parse_mode="Markdown"
            )
        except Exception:
            await query.edit_message_text(
                f"❌ *Order Ditolak*\n\n"
                f"👤 {order['nama']} (@{order['username']})\n"
                f"📦 {order['plan']} — {format_rupiah(order['total_bayar'])}",
                parse_mode="Markdown"
            )

        await ctx.bot.send_message(
            order["user_id"],
            f"❌ *Pembayaran ditolak.*\n\n"
            f"Kemungkinan:\n"
            f"• Nominal tidak sesuai\n"
            f"• Bukti tidak valid\n\n"
            f"Hubungi admin: {KONTAK}",
            parse_mode="Markdown",
            reply_markup=main_keyboard()
        )
        await audit_event(ctx, "❌ Order Ditolak", [
            f"👤 User    : {order['nama']} (@{order['username']}) | ID: {order['user_id']}",
            f"📦 Paket   : {order['plan']}",
            f"💵 Total   : {format_rupiah(order['total_bayar'])}",
            f"🆔 Order ID: {order_id}",
        ])
        return

    # ── KONFIRMASI ──
    kode_aktivasi = buat_kode_aktivasi()
    waktu_aktif   = datetime.now()
    waktu_expire  = waktu_aktif + timedelta(days=order["durasi"])
    motion_plan   = order.get("motion_plan", "basic")

    simpan_kode_ke_motion(kode_aktivasi, motion_plan, waktu_expire.timestamp())

    db["aktivasi"][kode_aktivasi] = {
        "kode"       : kode_aktivasi,
        "user_id"    : order["user_id"],
        "plan"       : order["plan"],
        "motion_plan": motion_plan,
        "durasi"     : order["durasi"],
        "expire"     : waktu_expire.strftime("%d/%m/%Y %H:%M"),
        "expire_ts"  : waktu_expire.timestamp(),
        "sudah_pakai": False,
        "order_id"   : order_id,
    }
    db["orders"][order_id]["status"]        = "dikonfirmasi"
    db["orders"][order_id]["kode_aktivasi"] = kode_aktivasi
    save_db(db)

    try:
        await query.edit_message_caption(
            f"✅ *Dikonfirmasi!*\n\n"
            f"👤 {order['nama']} (@{order['username']})\n"
            f"📦 {order['plan']} — {format_rupiah(order['total_bayar'])}\n"
            f"🔑 Kode: `{kode_aktivasi}`\n"
            f"⏳ Expire: {waktu_expire.strftime('%d/%m/%Y %H:%M')}\n\n"
            f"_Kode sudah dikirim ke user._",
            parse_mode="Markdown"
        )
    except Exception:
        await query.edit_message_text(
            f"✅ *Dikonfirmasi!*\n\n"
            f"👤 {order['nama']} (@{order['username']})\n"
            f"📦 {order['plan']} — {format_rupiah(order['total_bayar'])}\n"
            f"🔑 Kode: `{kode_aktivasi}`\n"
            f"⏳ Expire: {waktu_expire.strftime('%d/%m/%Y %H:%M')}\n\n"
            f"_Kode sudah dikirim ke user._",
            parse_mode="Markdown"
        )

    await ctx.bot.send_message(
        order["user_id"],
        f"🎉 *Pembayaran Terverifikasi!*\n\n"
        f"📦 Paket   : *{order['plan']}*\n"
        f"⏳ Berlaku : {order['durasi']} hari\n"
        f"📅 Expire  : {waktu_expire.strftime('%d/%m/%Y %H:%M')}\n\n"
        f"🔑 *Kode Aktivasi kamu:*\n"
        f"`{kode_aktivasi}`\n\n"
        f"⚠️ _Kode hanya berlaku *1 kali* dan berlaku sampai expire._\n"
        f"Masukkan kode ini di *Bot Motion Control* untuk aktifkan akses.\n\n"
        f"Terima kasih telah berlangganan *NS STORE* 🙏",
        parse_mode="Markdown",
        reply_markup=main_keyboard()
    )
    await audit_event(ctx, "✅ Order Dikonfirmasi", [
        f"👤 User    : {order['nama']} (@{order['username']}) | ID: {order['user_id']}",
        f"📦 Paket   : {order['plan']}",
        f"💵 Total   : {format_rupiah(order['total_bayar'])}",
        f"🔑 Kode    : {kode_aktivasi}",
        f"📅 Expire  : {waktu_expire.strftime('%d/%m/%Y %H:%M')}",
        f"🆔 Order ID: {order_id}",
    ])

# ─────────────────────────────────────────────
# STATUS AKSES
# ─────────────────────────────────────────────
async def status_akses(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    user_id = update.effective_user.id
    db = load_db()

    order_aktif = None
    for o in db["orders"].values():
        if o["user_id"] == user_id and o["status"] == "dikonfirmasi":
            order_aktif = o
            break

    if not order_aktif:
        for o in db["orders"].values():
            if o["user_id"] == user_id and o["status"] == "menunggu_verifikasi":
                await update.message.reply_text(
                    "📊 *Status Order*\n\n"
                    "⏳ Bukti transfer sedang diverifikasi admin.\n"
                    "Sabar ya, kode aktivasi segera dikirim! 🙏",
                    parse_mode="Markdown",
                    reply_markup=main_keyboard()
                )
                return

        await update.message.reply_text(
            "📊 *Status Akses*\n\n"
            "❌ Belum ada akses aktif.\n"
            "Pilih *📦 Pilih Plan* untuk berlangganan.",
            parse_mode="Markdown",
            reply_markup=main_keyboard()
        )
        return

    kode = order_aktif.get("kode_aktivasi", "-")
    aktivasi_data = db["aktivasi"].get(kode, {})
    sudah_pakai = aktivasi_data.get("sudah_pakai", False)

    if sudah_pakai:
        expire_ts = aktivasi_data.get("expire_ts", 0)
        expire_dt = datetime.fromtimestamp(expire_ts)
        sisa = expire_dt - datetime.now()
        if sisa.total_seconds() > 0:
            jam   = int(sisa.total_seconds() // 3600)
            menit = int((sisa.total_seconds() % 3600) // 60)
            status_teks = f"✅ *AKTIF* — Sisa {jam} jam {menit} menit"
        else:
            status_teks = "❌ *KADALUARSA*"
    else:
        status_teks = "⏳ *BELUM DIAKTIVASI di Motion Bot*"

    await update.message.reply_text(
        f"📊 *STATUS AKSES KAMU*\n"
        f"─────────────────────\n"
        f"📦 Paket  : {order_aktif['plan']}\n"
        f"🔰 Status : {status_teks}\n"
        f"🔑 Kode   : `{kode}`\n"
        f"⏳ Expire : {aktivasi_data.get('expire', '-')}\n"
        f"─────────────────────\n"
        f"{'Masukkan kode di Bot Motion Control.' if not sudah_pakai else ''}",
        parse_mode="Markdown",
        reply_markup=main_keyboard()
    )

