# ─────────────────────────────────────────────
# ADMIN: Set QRIS via bot (opsional — kirim foto ke bot saat jadi admin)
# Jalankan /setqris lalu kirim foto QRIS untuk update base64 otomatis
# ─────────────────────────────────────────────
SET_QRIS_WAIT = 99

async def cmd_setqris(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    if update.effective_user.id != ADMIN_ID:
        return
    ctx.user_data["set_qris"] = True
    await update.message.reply_text(
        "📷 Kirim foto QRIS baru kamu sekarang.\n\n"
        "Bot akan encode otomatis dan simpan ke config.\n"
        "_(Gunakan ini supaya tidak perlu edit file manual)_",
        parse_mode="Markdown"
    )
    return SET_QRIS_WAIT

async def terima_qris_baru(update: Update, ctx: ContextTypes.DEFAULT_TYPE):
    if update.effective_user.id != ADMIN_ID or not ctx.user_data.get("set_qris"):
        return ConversationHandler.END
    if not update.message.photo:
        await update.message.reply_text("Kirim *foto* QRIS ya.", parse_mode="Markdown")
        return SET_QRIS_WAIT

    # Download foto dari Telegram
    import requests as req
    file_id = update.message.photo[-1].file_id
    bot_token = BOT_TOKEN
    r1 = req.get(f"https://api.telegram.org/bot{bot_token}/getFile", params={"file_id": file_id}, timeout=30)
    file_path = r1.json()["result"]["file_path"]
    r2 = req.get(f"https://api.telegram.org/file/bot{bot_token}/{file_path}", timeout=30)
    img_bytes = r2.content
    b64 = base64.b64encode(img_bytes).decode()

    # Simpan ke file config_qris.txt agar admin bisa copy-paste ke QRIS_BASE64
    with open("config_qris.txt", "w") as f:
        f.write(b64)

    await update.message.reply_text(
        f"✅ *QRIS berhasil di-encode!*\n\n"
        f"Base64 disimpan ke file `config_qris.txt`\n\n"
        f"*Cara pakai:*\n"
        f"1. Buka `config_qris.txt`\n"
        f"2. Copy semua isinya\n"
        f"3. Paste ke `QRIS_BASE64 = \"...\"` di script\n"
        f"4. Restart bot\n\n"
        f"Atau gunakan preview 50 karakter pertama:\n"
        f"`{b64[:50]}...`",
        parse_mode="Markdown",
        reply_markup=main_keyboard()
    )
    ctx.user_data.clear()
    return ConversationHandler.END

# ─────────────────────────────────────────────
# STARTUP / SHUTDOWN NOTIFICATION
# ─────────────────────────────────────────────
async def on_startup(app):
    if not HISTORY_CHANNEL_ID:
        return
    try:
        await app.bot.send_message(
            chat_id=HISTORY_CHANNEL_ID,
            text=f"🟢 NS Store Bot aktif — {datetime.now().strftime('%d/%m/%Y %H:%M:%S')}"
        )
    except Exception as e:
        logging.warning("startup notif gagal: %s", e)

async def on_shutdown(app):
    if not HISTORY_CHANNEL_ID:
        return
    try:
        await app.bot.send_message(
            chat_id=HISTORY_CHANNEL_ID,
            text=f"🔴 NS Store Bot berhenti — {datetime.now().strftime('%d/%m/%Y %H:%M:%S')}"
        )
    except Exception:
        pass

# ─────────────────────────────────────────────
# MAIN
# ─────────────────────────────────────────────
def main():
    app = Application.builder().token(BOT_TOKEN).post_init(on_startup).post_stop(on_shutdown).build()

    conv_order = ConversationHandler(
        entry_points=[MessageHandler(filters.Regex("^📦 Pilih Plan$"), pilih_plan)],
        states={
            PILIH_PLAN: [
                MessageHandler(filters.Regex("^(1|2|3|❌ Batal)$"), proses_plan),
            ],
            TUNGGU_BUKTI: [
                MessageHandler(filters.PHOTO | filters.Document.IMAGE, terima_bukti),
                MessageHandler(filters.TEXT & ~filters.COMMAND, bukti_bukan_foto),
            ],
        },
        fallbacks=[MessageHandler(filters.Regex("^❌ Batal$"), batal)],
        allow_reentry=True,
    )

    conv_setqris = ConversationHandler(
        entry_points=[CommandHandler("setqris", cmd_setqris)],
        states={
            SET_QRIS_WAIT: [
                MessageHandler(filters.PHOTO, terima_qris_baru),
                MessageHandler(filters.TEXT & ~filters.COMMAND, lambda u, c: None),
            ]
        },
        fallbacks=[],
    )

    app.add_handler(CommandHandler("start", start))
    app.add_handler(conv_setqris)
    app.add_handler(conv_order)
    app.add_handler(CallbackQueryHandler(admin_callback, pattern=r"^(ok|tolak)_"))
    app.add_handler(MessageHandler(filters.Regex("^❓ Cara Order$"),      cara_order))
    app.add_handler(MessageHandler(filters.Regex("^📊 Status Akses$"),    status_akses))
    app.add_handler(MessageHandler(filters.Regex("^📞 Kontak Admin$"),    kontak_admin))
    app.add_handler(MessageHandler(filters.Regex("^ℹ️ Pusat Informasi$"), pusat_info))

    print("🤖 NS STORE BOT ORDER aktif!")
    print("Tekan Ctrl+C untuk berhenti.")
    app.run_polling()

if __name__ == "__main__":
    main()
